import{_ as t,o as r,c as a,ai as s}from"./chunks/framework.LYGRWSbL.js";const b=JSON.parse('{"title":"Le participe passé","description":"","frontmatter":{},"headers":[],"relativePath":"module-4-le-temps/participe-passe.md","filePath":"module-4-le-temps/participe-passe.md","lastUpdated":1773298982000}'),n={name:"module-4-le-temps/participe-passe.md"};function l(d,e,o,i,c,p){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="le-participe-passe" tabindex="-1">Le participe passé <a class="header-anchor" href="#le-participe-passe" aria-label="Permalink to “Le participe passé”">​</a></h1><p><strong>Prérequis :</strong> <a href="./perfekt.html">Le Perfekt</a></p><p><strong>Objectif :</strong> former correctement le participe passé des verbes réguliers et connaître les irréguliers essentiels.</p><p>Le participe passé (Partizip II) est la deuxième pièce du Perfekt. Sa formation suit des règles prévisibles pour les verbes réguliers, mais les irréguliers sont à apprendre.</p><h2 id="verbes-reguliers-ge-radical-t" tabindex="-1">Verbes réguliers : ge- + radical + -t <a class="header-anchor" href="#verbes-reguliers-ge-radical-t" aria-label="Permalink to “Verbes réguliers : ge- + radical + -t”">​</a></h2><p>La formule est simple : on prend le radical (infinitif sans <em>-en</em>), on ajoute <em>ge-</em> devant et <em>-t</em> derrière.</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Infinitif</th><th class="p-3 text-left font-semibold text-gray-600">Radical</th><th class="p-3 text-center font-semibold text-green-700">Participe passé</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3">machen</td><td class="p-3 text-gray-500">mach-</td><td class="p-3 text-center font-bold text-green-700">gemacht</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3">spielen</td><td class="p-3 text-gray-500">spiel-</td><td class="p-3 text-center font-bold text-green-700">gespielt</td></tr><tr class="border-t border-gray-100"><td class="p-3">kaufen</td><td class="p-3 text-gray-500">kauf-</td><td class="p-3 text-center font-bold text-green-700">gekauft</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3">lernen</td><td class="p-3 text-gray-500">lern-</td><td class="p-3 text-center font-bold text-green-700">gelernt</td></tr><tr class="border-t border-gray-100"><td class="p-3">arbeiten</td><td class="p-3 text-gray-500">arbeit-</td><td class="p-3 text-center font-bold text-green-700">gearbeitet</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3">warten</td><td class="p-3 text-gray-500">wart-</td><td class="p-3 text-center font-bold text-green-700">gewartet</td></tr></tbody></table></div><div class="info custom-block"><p class="custom-block-title">Radicaux en -t ou -d : on intercale un <em>-e-</em></p><p>Même règle qu&#39;au présent : <em>arbeiten</em> → <em>gearbeit<strong>e</strong>t</em>, <em>warten</em> → <em>gewart<strong>e</strong>t</em>. Le <em>-e-</em> est la pour faciliter la prononciation.</p></div><h2 id="deux-cas-ou-ge-n-apparait-pas" tabindex="-1">Deux cas où <em>ge-</em> n&#39;apparaît pas <a class="header-anchor" href="#deux-cas-ou-ge-n-apparait-pas" aria-label="Permalink to “Deux cas où ge- n&#39;apparaît pas”">​</a></h2><h3 id="verbes-en-ieren" tabindex="-1">Verbes en -ieren <a class="header-anchor" href="#verbes-en-ieren" aria-label="Permalink to “Verbes en -ieren”">​</a></h3><p>Les verbes d&#39;origine étrangère termines par <em>-ieren</em> ne prennent pas <em>ge-</em> : radical + <em>-t</em>.</p><ul><li><em>telefonieren</em> → <em>telefoniert</em></li><li><em>studieren</em> → <em>studiert</em></li><li><em>passieren</em> → <em>passiert</em></li><li><em>reservieren</em> → <em>reserviert</em></li></ul><h3 id="verbes-a-prefixe-non-separable" tabindex="-1">Verbes à préfixe non séparable <a class="header-anchor" href="#verbes-a-prefixe-non-separable" aria-label="Permalink to “Verbes à préfixe non séparable”">​</a></h3><p>Les verbes avec préfixe non séparable (<em>be-, ge-, er-, ver-, zer-, ent-, emp-, miss-</em>) ne prennent pas <em>ge-</em> non plus : le préfixe + radical + <em>-t</em>.</p><ul><li><em>bezahlen</em> → <em>bezahlt</em></li><li><em>besuchen</em> → <em>besucht</em></li><li><em>verkaufen</em> → <em>verkauft</em></li><li><em>verstehen</em> → <em>verstanden</em> (irrégulier)</li></ul><h2 id="verbes-separables-ge-s-intercale" tabindex="-1">Verbes séparables : ge- s&#39;intercale <a class="header-anchor" href="#verbes-separables-ge-s-intercale" aria-label="Permalink to “Verbes séparables : ge- s&#39;intercale”">​</a></h2><p>Pour les verbes séparables, le <em>ge-</em> s&#39;insere entre le préfixe et le radical :</p><ul><li><em>aufmachen</em> → <em>auf<strong>ge</strong>macht</em></li><li><em>anrufen</em> → <em>an<strong>ge</strong>rufen</em></li><li><em>einkaufen</em> → <em>ein<strong>ge</strong>kauft</em></li><li><em>aufstehen</em> → <em>auf<strong>ge</strong>standen</em></li></ul><h2 id="verbes-irreguliers-a-connaitre" tabindex="-1">Verbes irréguliers à connaître <a class="header-anchor" href="#verbes-irreguliers-a-connaitre" aria-label="Permalink to “Verbes irréguliers à connaître”">​</a></h2><p>Les irréguliers changent souvent la voyelle du radical et prennent <em>-en</em> au lieu de <em>-t</em>.</p><div class="mt-4 grid grid-cols-2 gap-4"><div class="overflow-hidden rounded-xl border border-gray-200"><div class="bg-gray-50 p-2 text-center text-xs font-semibold text-gray-600 uppercase tracking-wide">avec haben</div><table class="w-full text-sm"><tbody><tr class="border-t border-gray-100"><td class="p-2">essen</td><td class="p-2 text-center font-bold text-green-700">gegessen</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">trinken</td><td class="p-2 text-center font-bold text-green-700">getrunken</td></tr><tr class="border-t border-gray-100"><td class="p-2">sehen</td><td class="p-2 text-center font-bold text-green-700">gesehen</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">schreiben</td><td class="p-2 text-center font-bold text-green-700">geschrieben</td></tr><tr class="border-t border-gray-100"><td class="p-2">lesen</td><td class="p-2 text-center font-bold text-green-700">gelesen</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">nehmen</td><td class="p-2 text-center font-bold text-green-700">genommen</td></tr><tr class="border-t border-gray-100"><td class="p-2">geben</td><td class="p-2 text-center font-bold text-green-700">gegeben</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">sprechen</td><td class="p-2 text-center font-bold text-green-700">gesprochen</td></tr><tr class="border-t border-gray-100"><td class="p-2">finden</td><td class="p-2 text-center font-bold text-green-700">gefunden</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">haben</td><td class="p-2 text-center font-bold text-green-700">gehabt</td></tr></tbody></table></div><div class="overflow-hidden rounded-xl border border-gray-200"><div class="bg-gray-50 p-2 text-center text-xs font-semibold text-gray-600 uppercase tracking-wide">avec sein</div><table class="w-full text-sm"><tbody><tr class="border-t border-gray-100"><td class="p-2">gehen</td><td class="p-2 text-center font-bold text-green-700">gegangen</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">kommen</td><td class="p-2 text-center font-bold text-green-700">gekommen</td></tr><tr class="border-t border-gray-100"><td class="p-2">fahren</td><td class="p-2 text-center font-bold text-green-700">gefahren</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">fliegen</td><td class="p-2 text-center font-bold text-green-700">geflogen</td></tr><tr class="border-t border-gray-100"><td class="p-2">laufen</td><td class="p-2 text-center font-bold text-green-700">gelaufen</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">bleiben</td><td class="p-2 text-center font-bold text-green-700">geblieben</td></tr><tr class="border-t border-gray-100"><td class="p-2">sein</td><td class="p-2 text-center font-bold text-green-700">gewesen</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">werden</td><td class="p-2 text-center font-bold text-green-700">geworden</td></tr><tr class="border-t border-gray-100"><td class="p-2">aufstehen</td><td class="p-2 text-center font-bold text-green-700">aufgestanden</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-2">einschlafen</td><td class="p-2 text-center font-bold text-green-700">eingeschlafen</td></tr></tbody></table></div></div><div class="tip custom-block"><p class="custom-block-title">Apprendre par groupes de voyelle</p><p>Les irréguliers changent souvent la voyelle du radical de façon systématique. <em>trinken → getrunken</em>, <em>finden → gefunden</em>, <em>singen → gesungen</em> : le groupe <em>-in- → -un-</em> est courant. Apprendre par patterns plutot qu&#39;un par un accelère la mémorisation.</p></div>',22)])])}const m=t(n,[["render",l]]);export{b as __pageData,m as default};
